CREATE & ALTER:
  CREATE DATABASE company;
  USE company;
  CREATE TABLE employees (
    id INT AUTO_INCREMENT PRIMARY KEY,
    name VARCHAR(100) NOT NULL,
    dept_id INT,
    salary DECIMAL(10,2),
    hire_date DATE,
    FOREIGN KEY (dept_id) REFERENCES departments(id)
  );
  ALTER TABLE employees ADD COLUMN email VARCHAR(200);
  ALTER TABLE employees MODIFY salary DECIMAL(12,2);

INSERT / UPDATE / DELETE:
  INSERT INTO employees (name, dept_id, salary) VALUES ('Alice', 1, 75000);
  UPDATE employees SET salary = salary * 1.1 WHERE dept_id = 1;
  DELETE FROM employees WHERE salary < 30000;

SELECT:
  SELECT * FROM employees;
  SELECT name, salary FROM employees WHERE salary > 50000;
  SELECT * FROM employees WHERE dept_id IN (1, 2, 3);
  SELECT * FROM employees WHERE name LIKE 'A%';  -- starts with A
  SELECT * FROM employees WHERE hire_date BETWEEN '2020-01-01' AND '2023-12-31';
  SELECT * FROM employees ORDER BY salary DESC LIMIT 10;

AGGREGATIONS:
  SELECT COUNT(*) FROM employees;
  SELECT dept_id, COUNT(*) as headcount, AVG(salary) as avg_sal,
         MAX(salary), MIN(salary), SUM(salary)
  FROM employees GROUP BY dept_id
  HAVING AVG(salary) > 60000
  ORDER BY avg_sal DESC;

JOINS:
  INNER JOIN — only matching rows in both tables
  LEFT JOIN  — all left rows + matching right (NULLs for no match)
  RIGHT JOIN — all right rows + matching left
  FULL JOIN  — all rows from both (MySQL uses UNION for this)

  SELECT e.name, d.name as dept FROM employees e
  INNER JOIN departments d ON e.dept_id = d.id;

INDEXES:
  CREATE INDEX idx_salary ON employees(salary);  -- speeds up WHERE salary =
  UNIQUE INDEX — enforces uniqueness
  COMPOSITE INDEX — multiple columns
  Indexes speed reads but slow writes/updates. Index columns used in WHERE/JOIN.

VIEWS:
  CREATE VIEW high_earners AS
  SELECT name, salary FROM employees WHERE salary > 80000;
  SELECT * FROM high_earners;  -- use like a table

TRIGGERS:
  DELIMITER //
  CREATE TRIGGER audit_salary AFTER UPDATE ON employees
  FOR EACH ROW BEGIN
    INSERT INTO salary_log(emp_id, old_sal, new_sal, changed_at)
    VALUES (OLD.id, OLD.salary, NEW.salary, NOW());
  END //
  DELIMITER ;

TRANSACTIONS:
  START TRANSACTION;
  UPDATE accounts SET balance = balance - 500 WHERE id = 1;
  UPDATE accounts SET balance = balance + 500 WHERE id = 2;
  COMMIT;  -- or ROLLBACK; if error

DATE FUNCTIONS:
  NOW(), CURDATE(), CURTIME()
  DATE_ADD(date, INTERVAL 7 DAY)
  DATEDIFF(end, start)
  YEAR(date), MONTH(date), DAY(date)
  DATE_FORMAT(date, '%d/%m/%Y')

